using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF Core 9: HasIndex throws on Cosmos entities — removed.
            // Manage indexing via Azure Portal / Bicep / Terraform instead.

            // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
            // Keep the old name so existing documents are still recognized.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id no longer includes discriminator prefix ("Blog|1" → "1").
            // Keep the old compound format so existing documents remain accessible.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

